import{c as e,a7 as r,y as a,B as d}from"./chunks/framework.BYQtDGaq.js";const s=JSON.parse('{"title":"OpenRLHF & veRL 参数转换指南","description":"对照说明 OpenRLHF 和 veRL 两个框架之间的训练参数映射关系","frontmatter":{"title":"OpenRLHF & veRL 参数转换指南","description":"对照说明 OpenRLHF 和 veRL 两个框架之间的训练参数映射关系"},"headers":[],"relativePath":"rlhf/frameworks/openrlhf-verl-params.md","filePath":"rlhf/frameworks/openrlhf-verl-params.md","lastUpdated":1782721961000}'),o={name:"rlhf/frameworks/openrlhf-verl-params.md"};function p(i,t,l,_,c,n){return r(),a("div",null,[...t[0]||(t[0]=[d('<h2 id="openrlhf-verl-参数转换" tabindex="-1">OpenRLHF &amp; veRL 参数转换 <a class="header-anchor" href="#openrlhf-verl-参数转换" aria-label="Permalink to “OpenRLHF &amp; veRL 参数转换”">​</a></h2><h3 id="模型参数" tabindex="-1">模型参数 <a class="header-anchor" href="#模型参数" aria-label="Permalink to “模型参数”">​</a></h3><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>介绍</th><th>OpenRLHF</th><th>veRL</th></tr></thead><tbody><tr><td>Actor 模型路径</td><td>pretrain</td><td>actor_rollout_ref.model.path</td></tr><tr><td>Reward 模型路径</td><td>reward_pretrain</td><td>reward_model.model.path</td></tr><tr><td>Critic 模型路径</td><td>critic_pretrain</td><td>critic.model.path</td></tr></tbody></table></div><h3 id="优化参数" tabindex="-1">优化参数 <a class="header-anchor" href="#优化参数" aria-label="Permalink to “优化参数”">​</a></h3><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>介绍</th><th>OpenRLHF</th><th>veRL</th></tr></thead><tbody><tr><td>Actor 模型学习率</td><td>actor_learning_rate</td><td>actor_rollout_ref.actor.optim.lr</td></tr><tr><td>Critic 模型学习率</td><td>critic_learning_rate</td><td>critic.optim.lr</td></tr></tbody></table></div><p><a href="https://github.com/OpenRLHF/OpenRLHF" target="_blank" rel="noreferrer">OpenRLHF</a> 默认使用的是 Warmup-Decay 的学习率调度器，所以也支持设置 warmup 步数等其他的相关参数，具体的可以在 <a href="https://github.com/OpenRLHF/OpenRLHF/blob/main/openrlhf/cli/train_ppo_ray.py" target="_blank" rel="noreferrer">train_ppo_ray.py</a> 中找到相关的参数。</p><p>veRL 中对于学习率的调度方式可以选择为 <code>constant/cosine</code>，在 YAML 文件中依然可以找对应的<a href="https://github.com/volcengine/verl/blob/f8acd9017b4db4eead1f34beb39fce9c39143194/verl/trainer/config/ppo_trainer.yaml%23L45" target="_blank" rel="noreferrer">位置</a>。</p><h3 id="数据参数" tabindex="-1">数据参数 <a class="header-anchor" href="#数据参数" aria-label="Permalink to “数据参数”">​</a></h3><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>介绍</th><th>OpenRLHF</th><th>veRL</th></tr></thead><tbody><tr><td>训练阶段单卡分配的 experience 数量</td><td>micro_train_batch_size</td><td>actor_rollout_ref.actor.ppo_micro_batch_size_per_gpu</td></tr><tr><td>训练时全局的 experience 数量</td><td>train_batch_size</td><td>actor_rollout_ref.actor.ppo_mini_batch_size*actor_rollout_ref.rollout.n(本节末有解释)</td></tr><tr><td>探索阶段单卡分配的 experience 数量</td><td>micro_rollout_batch_size</td><td>(自动计算)</td></tr><tr><td>探索阶段的 prompt 数量</td><td>rollout_batch_size</td><td>data.train_batch_size</td></tr><tr><td>实际使用的最大 prompt 数量</td><td>max_samples</td><td>\\</td></tr><tr><td>单个 prompt 采样次数</td><td>n_samples_per_prompt</td><td>actor_rollout_ref.rollout.n</td></tr><tr><td>训练阶段 experience 的学习次数</td><td>max_epochs</td><td>actor_rollout_ref.actor.ppo_epochs</td></tr><tr><td>数据集迭代次数</td><td>num_episodes</td><td>trainer.total_epochs</td></tr></tbody></table></div><h4 id="openrlhf-流程" tabindex="-1">OpenRLHF 流程： <a class="header-anchor" href="#openrlhf-流程" aria-label="Permalink to “OpenRLHF 流程：”">​</a></h4><p>(1) 首先，当给定一个数据集之后，框架会从中选择至多 max_samples 个 prompt。假设我们的数据集仅有 1024 个 prompt，并且 1024 小于 max_samples，则 1024 个 prompt 全部保留。</p><p>(2) 之后进入探索阶段，由于一次探索完 1024 个 prompt 的时间太长，所以选择一次只对 rollout_batch_size 个 prompt 进行探索。我们假设 rollout_batch_size 为 32，则一共需要探索 1024 ÷32=32 步。这个 32 步就是我们在 wandb 或者 tensorboard 上面看到的步骤，我们称之为 explore step。我们会用 vLLM 对每个 prompt 进行采样 n_samples_per_prompt 次，得到所有的 samples。我们假设 n_samples_per_prompt 为 8，则得到了 32 ×8=256 个样本，即每个样本都是一个问答对，一共有 32 个问题，并且相同的问题回答了 8 次。</p><p>(3) 之后需要生成 experience，这时就需要切换到训练引擎，即在 1 步内单卡负责生成 micro_rollout_batch_size 个经验，我们假设 micro_rollout_batch_size 为 4，我们有 8 张卡，则 1 步一共可以生成 32 个 experience。由于我们一共有 256 个样本，所以需要一共需要 256 ÷32=8 步可以得到全部的 experience。在 make experience 阶段我们主要利用 Reward 模型得到每个答案的奖励分数、用 Critic 模型给出每个答案每一步的 Value 值（如果有 Critic 模型），以及用 Reference 模型和 Actor 模型给出每个答案每一步的预测概率并且计算出对应的 KL 惩罚值（如果有 Reference 模型）</p><p>(4) 在结束探索阶段后，就进入了训练阶段。刚才一共得到了 256 个 experience，但是我们的显卡不足以一次性在所有的样本上进行训练，因此我们设置 train_batch_size 为 128，即每次只更新 128 个 experience，则需要 256 ÷128=2 步，也就是说在训练阶段模型更新了 2 次，我们称之为 update step。假设 micro_train_batch_size 为 4，我们有 8 张卡，则 1 步一共可以训练 32 个 experience，那么我们需要 4 步梯度累计，然后才进行反向传播。当 update step 大于 1，也就是所有的 experience 不能一次更新完的时候，就称之为 off policy，反之如果 update step=1，也就是模型探索一步就更新一步，则称之为 on policy。并且需要注意，如果 max_epochs ＞ 1，此时这一组经验被训练了多次，即对 256 个 experience 进行了多次优化，那么此时的策略一定是 off policy，所以一般情况下我们默认这个参数为 1 即可，因为我们希望尽可能地确保我们的优化是 on policy 的。</p><p>(5) 我们再强调一遍，我们的数据集有 1024 个 prompt，每次探索和训练其中的 32 个，则经过以上流程循环 1024 ÷32=32 步，我们已经探索并且训练完了整个数据集，之后我们再训练 num_episodes 次，则完成了整个训练流程。</p><h4 id="verl-流程" tabindex="-1">veRL 流程 <a class="header-anchor" href="#verl-流程" aria-label="Permalink to “veRL 流程”">​</a></h4><p>veRL 流程上，从算法逻辑上与 OpenRLHF 的是相同的，但是其中需要关注的是 <code>actor_rollout_ref.actor.ppo_mini_batch_size</code> 参数是一个与采样数 <code>n</code> 无关的参数，从上述的 1024 个 prompt 的数据集来看，如果 <code>ppo_mini_batch_size</code> 的设置为 32 的话，则一定进行 1024 ÷32=32 次的参数更新，无论 <code>sample_n</code> 的设置值为多少。</p><p>但要注意， veRL 中的 <code>ppo_micro_batch_size_per_gpu</code> 是已经考虑了 <code>sample_n</code>，因此又重新对 OpenRLHF 的参数含义相同。</p><h3 id="批处理参数部分" tabindex="-1">批处理参数部分 <a class="header-anchor" href="#批处理参数部分" aria-label="Permalink to “批处理参数部分”">​</a></h3><p>上文提到的 actor 的训练 bs 设置不再赘述。</p><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>介绍</th><th>OpenRLHF</th><th>veRL</th></tr></thead><tbody><tr><td>rollout 计算 log_prob 时每个 GPU 的微批量大小</td><td>micro_train_batch_size</td><td>actor_rollout_ref.rollout.log_prob_micro_batch_size_per_gpu</td></tr><tr><td>ref 计算 log_prob 时每个 GPU 的微批量大小</td><td>micro_train_batch_size</td><td>actor_rollout_ref.ref.log_prob_micro_batch_size_per_gpu</td></tr><tr><td>Critic 模型单 GPU 计算的批量大小</td><td>micro_train_batch_size</td><td>critic.forward_micro_batch_size_per_gpu</td></tr><tr><td>Reward 模型单 GPU 计算的批量大小</td><td>micro_train_batch_size</td><td>reward_model.micro_batch_size_per_gpu</td></tr></tbody></table></div><p>在 OpenRLHF 中，通常由 <code>micro_train_batch_size</code> 来管理所有的 bs 信息，对于不同的模型角色，实际上使用的是一个参数进行管理。但在 veRL 中，这个部分的参数则是可以指定的。一般来说如果脚本中不特地指定数值，则会保持与 <code>actor_rollout_ref.actor</code> 中设置一致。并且在 veRL 中，落实到 <code>per_gpu</code> 的参数设置，一般都是已经考虑了 sample_n 次的结果。</p><h3 id="生成参数" tabindex="-1">生成参数 <a class="header-anchor" href="#生成参数" aria-label="Permalink to “生成参数”">​</a></h3><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>介绍</th><th>OpenRLHF</th><th>veRL</th></tr></thead><tbody><tr><td>采样阶段的温度系数</td><td>temperature</td><td>rollout.temperature</td></tr><tr><td>prompt 最大长度</td><td>prompt_max_len</td><td>data.max_prompt_length</td></tr><tr><td>生成回答的最大长度</td><td>generate_max_len</td><td>data.max_response_length</td></tr></tbody></table></div>',24)])])}const m=e(o,[["render",p]]);export{s as __pageData,m as default};
